    },
    {
      "parameter": "ups.recovery_time_to_within_1_percent",
      "operator": "<=",
      "value": 20,
      "unit": "milliseconds",
      "condition": "during 100% load step transients",
      "quote": "Output voltage regulation shall be within +/- 1% of nominal under steady state conditions, and within +/- 5% during 100% load step transients, with recovery to +/- 1% within 20 milliseconds."
    }
